"use strict";(self.webpackChunkleetcode=self.webpackChunkleetcode||[]).push([[3769],{7040:e=>{e.exports=JSON.parse('{"tag":{"label":"array","permalink":"/leetcode/pt-BR/docs/tags/array","allTagsPath":"/leetcode/pt-BR/docs/tags","count":54,"items":[{"id":"problems/knapsack","title":"0/1 Knapsack Problem","description":"You\'ve broken into an art gallery and want to maximize the value of the paintings you steal. All the paintings you steal you place in your bag which can hold at most W pounds. Given that the weight and value of the ith painting is given by weights[i] and values[i] respectively, return the maximum value you can steal.","permalink":"/leetcode/pt-BR/docs/problems/knapsack"},{"id":"problems/three-sum","title":"3Sum","description":"Given a list of integers, nums, return a list containing all triplets that sum to zero.","permalink":"/leetcode/pt-BR/docs/problems/three-sum"},{"id":"problems/assign-cake","title":"Assign Cake","description":"This question is asked by Amazon. You are at a birthday party and are asked to distribute cake to your guests. Each guest is only satisfied if the size of the piece of cake they\'re given matches their appetite (i.e., is greater than or equal to their appetite). Given two arrays, appetite and cake where the ith element of appetite represents the ith guest\'s appetite, and the elements of cake represents the sizes of cake you have to distribute, return the maximum number of guests that you can satisfy.","permalink":"/leetcode/pt-BR/docs/problems/assign-cake"},{"id":"problems/best-time-to-buy-and-sell-stock-ii","title":"Best Time to Buy and Sell Stock II","description":"You are given the list of prices of a particular stock. Each element in the array represents the price of the stock at a given second throughout the current day. Return the maximum profit you can make trading this stock.","permalink":"/leetcode/pt-BR/docs/problems/best-time-to-buy-and-sell-stock-ii"},{"id":"problems/boats-to-save-people","title":"Boats to Save People","description":"This question is asked by Amazon. A ship is about to set sail and you are responsible for its safety precautions. More specifically, you are responsible for determining how many life rafts to carry onboard. You are given a list of all the passengers\' weights and are informed that a single life raft has a maximum capacity of limit and can hold at most two people. Return the minimum number of life rafts you must take onboard to ensure the safety of all your passengers.","permalink":"/leetcode/pt-BR/docs/problems/boats-to-save-people"},{"id":"problems/bricks-in-wheelbarrow","title":"Bricks in Wheelbarrow","description":"You are transporting bricks on a construction site and want to work as efficiently as possible. The weight of each brick is given by bricks[i]. Given a wheelbarrow that can carry up to (not including) 5000 pounds, return the maximum number of bricks you can place in your wheelbarrow to transport.","permalink":"/leetcode/pt-BR/docs/problems/bricks-in-wheelbarrow"},{"id":"problems/coin-change","title":"Coin Change","description":"This question is asked by Facebook. Given an array that represents different coin denominations and an amount of change you need to make, return the fewest number of coins it takes to make the given amount of change.","permalink":"/leetcode/pt-BR/docs/problems/coin-change"},{"id":"problems/combination-sum","title":"Combination Sum","description":"This question is asked by Apple. Given a list of positive numbers without duplicates and a target number, find all unique combinations of the numbers that sum to the target.","permalink":"/leetcode/pt-BR/docs/problems/combination-sum"},{"id":"problems/container-with-most-water","title":"Container With Most Water","description":"You are building a pool in your backyard and want to create the largest pool possible. The largest pool is defined as the pool that holds the most water. The workers you hired to dig the hole for your pool didn\'t do a great job and because of this the depths of the pool at different areas are not equal. Given an integer array of non-negative integers that represents a histogram of the different heights at each position of the hole for your pool, return the largest pool you can create.","permalink":"/leetcode/pt-BR/docs/problems/container-with-most-water"},{"id":"problems/contains-duplicate-ii","title":"Contains Duplicate II","description":"This question is asked by Google. Given an array, nums, and an integer k, return whether or not two unique indices exist such that nums[i] = nums[j] and the two indices i and j are at most k elements apart.","permalink":"/leetcode/pt-BR/docs/problems/contains-duplicate-ii"},{"id":"problems/count-partners","title":"Count Partners","description":"Given an integer array nums, return the total number of \\"partners\\" in the array.","permalink":"/leetcode/pt-BR/docs/problems/count-partners"},{"id":"problems/find-all-duplicates","title":"Find All Duplicates in Array","description":"Given an array of integers nums, each element in the array either appears once or twice. Return a list containing all the numbers that appear twice.","permalink":"/leetcode/pt-BR/docs/problems/find-all-duplicates"},{"id":"problems/first-bad-version","title":"First Bad Version","description":"This question is asked by Facebook. Releasing software can be tricky and sometimes we release new versions of our software with bugs. When we release a version with a bug it\'s referred to as a bad release. Your product manager has just informed you that a bug you created was released in one of the past versions and has caused all versions that have been released since to also be bad. Given that your past releases are numbered from zero to N and you have a helper function isBadRelease(int releaseNumber) that takes a version number and returns a boolean as to whether or not the given release number is bad, return the release number that your bug was initially shipped in.","permalink":"/leetcode/pt-BR/docs/problems/first-bad-version"},{"id":"problems/friend-circles","title":"Friend Circles","description":"This question is asked by Facebook. You are given a two dimensional matrix, friends, that represents relationships between coworkers in an office. If friendsi = 1 then coworker i is friends with coworker j and coworker j is friends with coworker i. Similarly if friendsi = 0 then coworker i is not friends with coworker j and coworker j is not friend with coworker i. Friendships in the office are transitive (i.e., if coworker one is friends with coworker two and coworker two is friends with coworker three, coworker one is also friends with coworker three). Given the friendships in the office defined by friends, return the total number of distinct friends groups in the office.","permalink":"/leetcode/pt-BR/docs/problems/friend-circles"},{"id":"problems/frog-jump","title":"Frog Jump","description":"A frog is attempting to cross a river to reach the other side. Within the river, there are stones located at different positions given by a stones array (this array is in sorted order). Starting on the first stone (i.e. stones[0]), the frog makes a jump of size one potentially landing on the next stone. If the frog\'s last jump was of size x, the frog\'s next jump may be of size x - 1, x, or x + 1. Given these following conditions return whether or not the frog can reach the other side.","permalink":"/leetcode/pt-BR/docs/problems/frog-jump"},{"id":"problems/k-closest-points-to-origin","title":"K Closest Points to Origin","description":"Given a list of points, return the k closest points to the origin (0, 0).","permalink":"/leetcode/pt-BR/docs/problems/k-closest-points-to-origin"},{"id":"problems/keyboard-row","title":"Keyboard Row","description":"Given a list of words, return all the words that require only a single row of a keyboard to type.","permalink":"/leetcode/pt-BR/docs/problems/keyboard-row"},{"id":"problems/kth-largest-element","title":"Kth Largest Element in an Array","description":"Given an array of integers, nums, and a value k, return the kth largest element.","permalink":"/leetcode/pt-BR/docs/problems/kth-largest-element"},{"id":"problems/labeled-items-max-sum","title":"Labeled Items Maximum Sum","description":"You are given a list of values and a list of labels. The ith element in labels represents the label of the ith element. Similarly, the ith element in values represents the value associated with the ith element (i.e. together, an \\"item\\" could be thought of as a label and a price).","permalink":"/leetcode/pt-BR/docs/problems/labeled-items-max-sum"},{"id":"problems/largest-pond-size","title":"Largest Pond Size","description":"You are given a two-dimensional matrix that represents a plot of land. Within the matrix there exist two values: ones which represent land and zeroes which represent water within a pond. Given that parts of a pond can be connected both horizontally and vertically (but not diagonally), return the largest pond size.","permalink":"/leetcode/pt-BR/docs/problems/largest-pond-size"},{"id":"problems/last-stone-weight","title":"Last Stone Weight","description":"This question is asked by Amazon. You are given a group of stones, all of which have a positive weight. At each turn, we select the heaviest two stones and smash them together. When smashing these two stones together, one of two things can happen:","permalink":"/leetcode/pt-BR/docs/problems/last-stone-weight"},{"id":"problems/lemonade-change","title":"Lemonade Change","description":"This question is asked by Amazon. You\'re running a popsicle stand where each popsicle costs $5. Each customer you encountered pays with either a $5 bill, a $10 bill, or a $20 bill and only buys a single popsicle. The customers that come to your stand come in the ordered given by the customers array where customers[i] represents the bill the ith customer pays with. Starting with $0, return whether or not you can serve all the given customers while also giving the correct amount of change.","permalink":"/leetcode/pt-BR/docs/problems/lemonade-change"},{"id":"problems/majority-element","title":"Majority Element","description":"High school students are voting for their class president and you\'re tasked with counting the votes. Each presidential candidate is represented by a unique integer and the candidate that should win the election is the candidate that has received more than half the votes. Given a list of integers, return the candidate that should become the class president.","permalink":"/leetcode/pt-BR/docs/problems/majority-element"},{"id":"problems/max-area-of-island","title":"Max Area of Island","description":"Given a 2D array grid, where zeroes represent water and ones represent land, return the size of the largest island.","permalink":"/leetcode/pt-BR/docs/problems/max-area-of-island"},{"id":"problems/maximum-length-concatenated-string","title":"Maximum Length of Concatenated String with Unique Characters","description":"Given an array of words, return the length of the longest phrase, containing only unique characters, that you can form by combining the given words together.","permalink":"/leetcode/pt-BR/docs/problems/maximum-length-concatenated-string"},{"id":"problems/maximum-points-from-coins","title":"Maximum Points You Can Obtain","description":"This question is asked by Google. You are given a bag of coins, an initial energy of E, and want to maximize your number of points (which starts at zero). To gain a single point you can exchange coins[i] amount of energy (i.e. if I have 100 energy and a coin that has a value 50 I can exchange 50 energy to gain a point). If you do not have enough energy you can give away a point in exchange for an increase in energy by coins[i] amount (i.e. you give away a point and your energy is increased by the value of that coin: energy += coins[i]). Return the maximum number of points you can gain.","permalink":"/leetcode/pt-BR/docs/problems/maximum-points-from-coins"},{"id":"problems/merge-intervals","title":"Merge Intervals","description":"Given a list of interval objects, merge all overlapping intervals and return the result.","permalink":"/leetcode/pt-BR/docs/problems/merge-intervals"},{"id":"problems/min-cost-climbing-stairs","title":"Min Cost Climbing Stairs","description":"This question is asked by Apple. Given a staircase where the ith step has a non-negative cost associated with it given by cost[i], return the minimum cost of climbing to the top of the staircase. You may climb one or two steps at a time and you may start climbing from either the first or second step.","permalink":"/leetcode/pt-BR/docs/problems/min-cost-climbing-stairs"},{"id":"problems/minimum-path-sum","title":"Minimum Path Sum","description":"This question is asked by Google. Given an N\xd7M matrix, grid, where each cell in the matrix represents the cost of stepping on the current cell, return the minimum cost to traverse from the top-left hand corner of the matrix to the bottom-right hand corner.","permalink":"/leetcode/pt-BR/docs/problems/minimum-path-sum"},{"id":"problems/missing-number","title":"Missing Number","description":"This question is asked by Amazon. Given an array that contains all distinct values from zero through N except one number, return the number that is missing from the array.","permalink":"/leetcode/pt-BR/docs/problems/missing-number"},{"id":"problems/monotonic-array","title":"Monotonic Array","description":"This question is asked by Facebook. Given an array nums, return whether or not its values are monotonically increasing or monotonically decreasing.","permalink":"/leetcode/pt-BR/docs/problems/monotonic-array"},{"id":"problems/move-zeroes","title":"Move Zeroes","description":"This question is asked by Apple. Given an array of numbers, move all zeroes in the array to the end while maintaining the relative order of the other numbers.","permalink":"/leetcode/pt-BR/docs/problems/move-zeroes"},{"id":"problems/number-of-islands","title":"Number of Islands","description":"Given a 2D array of integers with ones representing land and zeroes representing water, return the number of islands in the grid.","permalink":"/leetcode/pt-BR/docs/problems/number-of-islands"},{"id":"problems/number-of-ships","title":"Number of Ships in Harbor","description":"You\'re about to set sail off a pier and first want to count the number of ships that are already in the harbor. The harbor is deemed safe to sail in if the number of boats in the harbor is strictly less than limit. Given a 2D array that presents the harbor, where O represents water and S represents a ship, return whether or not it\'s safe for you to set sail.","permalink":"/leetcode/pt-BR/docs/problems/number-of-ships"},{"id":"problems/paint-house","title":"Paint House","description":"This question is asked by Apple. You are tasked with painting a row of houses in your neighborhood such that each house is painted either red, blue, or green. The cost of painting the ith house red, blue or green, is given by costsi, costsi, and costsi respectively. Given that you are required to paint each house and no two adjacent houses may be the same color, return the minimum cost to paint all the houses.","permalink":"/leetcode/pt-BR/docs/problems/paint-house"},{"id":"problems/path-with-maximum-gold","title":"Path with Maximum Gold","description":"This question is asked by Amazon. Given a 2D matrix that represents a gold mine, where each cell\'s value represents an amount of gold, return the maximum amount of gold you can collect given the following rules:","permalink":"/leetcode/pt-BR/docs/problems/path-with-maximum-gold"},{"id":"problems/plus-one","title":"Plus One","description":"Given an array digits that represents a non-negative integer, add one to the number and return the result as an array.","permalink":"/leetcode/pt-BR/docs/problems/plus-one"},{"id":"problems/predict-the-winner","title":"Predict the Winner","description":"This question is asked by Amazon. Given an integer array, two players take turns picking the largest number from the ends of the array. First, player one picks a number (either the left end or right end of the array) followed by player two. Each time a player picks a particular number, it is no longer available to the other player. This picking continues until all numbers in the array have been chosen. Once all numbers have been picked, the player with the larger score wins. Return whether or not player one will win.","permalink":"/leetcode/pt-BR/docs/problems/predict-the-winner"},{"id":"problems/product-of-array-except-self","title":"Product of Array Except Self","description":"Given an integer array nums, return an array where each element i represents the product of all values in nums excluding nums[i].","permalink":"/leetcode/pt-BR/docs/problems/product-of-array-except-self"},{"id":"problems/rabbit-holes","title":"Rabbit Holes Distance","description":"Given a 2D array containing only the following values: -1, 0, 1 where -1 represents an obstacle, 0 represents a rabbit hole, and 1 represents a rabbit, update every cell containing a rabbit with the distance to its closest rabbit hole.","permalink":"/leetcode/pt-BR/docs/problems/rabbit-holes"},{"id":"problems/remove-element","title":"Remove Element","description":"Given an integer array nums and a value val, remove all instances of val in-place and return the length of the new array.","permalink":"/leetcode/pt-BR/docs/problems/remove-element"},{"id":"problems/remove-vowels","title":"Remove Vowels from String","description":"This question is asked by Amazon. Given a string s, remove all the vowels it contains and return the resulting string.","permalink":"/leetcode/pt-BR/docs/problems/remove-vowels"},{"id":"problems/reverse-words","title":"Reverse Words in a String","description":"Given a string s, reverse the words.","permalink":"/leetcode/pt-BR/docs/problems/reverse-words"},{"id":"problems/rotate-image","title":"Rotate Image","description":"Given an image represented as a 2D array of pixels, return the image rotated 90 degrees clockwise.","permalink":"/leetcode/pt-BR/docs/problems/rotate-image"},{"id":"problems/rotting-oranges","title":"Rotting Oranges (Infection Spread)","description":"Given a 2D array where each cell can have one of three values:","permalink":"/leetcode/pt-BR/docs/problems/rotting-oranges"},{"id":"problems/shortest-distance-to-character","title":"Shortest Distance to Character","description":"Given a string s and a character c, return an array of integers where each index is the shortest distance from the character at that position to the nearest occurrence of c in the string.","permalink":"/leetcode/pt-BR/docs/problems/shortest-distance-to-character"},{"id":"problems/sort-array-by-parity-ii","title":"Sort Array By Parity II","description":"This question is asked by Amazon. Given an array of integers, nums, sort the array in any manner such that when i is even, nums[i] is even and when i is odd, nums[i] is odd.","permalink":"/leetcode/pt-BR/docs/problems/sort-array-by-parity-ii"},{"id":"problems/spiral-matrix","title":"Spiral Matrix","description":"Given a 2D matrix, return a list containing all of its elements in spiral order.","permalink":"/leetcode/pt-BR/docs/problems/spiral-matrix"},{"id":"problems/string-compression","title":"String Compression","description":"This question is asked by Facebook. Given a character array, compress it in place and return the new length of the array.","permalink":"/leetcode/pt-BR/docs/problems/string-compression"},{"id":"problems/third-maximum-number","title":"Third Maximum Number","description":"Given an array nums, return the third largest (distinct) value.","permalink":"/leetcode/pt-BR/docs/problems/third-maximum-number"},{"id":"problems/transpose-matrix","title":"Transpose Matrix","description":"Given a 2D matrix nums, return the matrix transposed.","permalink":"/leetcode/pt-BR/docs/problems/transpose-matrix"},{"id":"problems/two-city-scheduling","title":"Two City Scheduling","description":"This question is asked by Google. A company is booking flights to send its employees to its two satellite offices A and B. The cost of sending the ith employee to office A and office B is given by pricesi and pricesi respectively. Given that half the employees must be sent to office A and half the employees must be sent to office B, return the minimum cost the company must pay for all their employees\' flights.","permalink":"/leetcode/pt-BR/docs/problems/two-city-scheduling"},{"id":"problems/two-sum","title":"Two Sum","description":"Given an array of integers nums and an integer target, return indices of the two numbers such that they add up to target.","permalink":"/leetcode/pt-BR/docs/problems/two-sum"},{"id":"problems/word-search","title":"Word Search","description":"This question is asked by Amazon. Given a 2D board that represents a word search puzzle and a string word, return whether or the given word can be formed in the puzzle by only connecting cells horizontally and vertically.","permalink":"/leetcode/pt-BR/docs/problems/word-search"}],"unlisted":false}}')}}]);